const now = new Date();
const hour = now.getUTCHours();
const isMorning = hour < 17;
return [{ json: { run_type: isMorning ? 'MORNING' : 'EVENING', timestamp: now.toISOString() } }];

// Yahoo Finance /v8/finance/spark response parser with fallback
const raw = $input.first().json;

const names = {
  AAPL:  'Apple',
  META:  'Meta (Facebook)',
  GOOGL: 'Google (Alphabet)',
  MSFT:  'Microsoft',
  TSLA:  'Tesla',
  NVDA:  'NVIDIA',
  AMZN:  'Amazon',
};

// Try to parse Yahoo Finance response
let results = [];
const sparkMap = raw?.spark?.result || [];

if (sparkMap.length > 0) {
  results = sparkMap.map(entry => {
    const symbol   = entry.symbol;
    const response = entry.response?.[0] || {};
    const meta     = response.meta || {};
    const closes   = response.indicators?.quote?.[0]?.close || [];
    const close    = Math.round((meta.regularMarketPrice || closes[closes.length - 1] || 0) * 100) / 100;
    const prevClose = Math.round((meta.chartPreviousClose || meta.previousClose || close) * 100) / 100;
    const dayChange = Math.round((close - prevClose) * 100) / 100;
    const pct       = prevClose > 0 ? Math.round((dayChange / prevClose) * 10000) / 100 : 0;

    return {
      ticker:     symbol,
      name:       names[symbol] || symbol,
      open:       Math.round((meta.regularMarketOpen || prevClose) * 100) / 100,
      close,
      high:       Math.round((meta.regularMarketDayHigh || close) * 100) / 100,
      low:        Math.round((meta.regularMarketDayLow  || close) * 100) / 100,
      prev_close: prevClose,
      day_change: dayChange,
      day_pct:    pct,
      volume:     meta.regularMarketVolume || 0,
      direction:  pct >= 0 ? 'UP' : 'DOWN',
      is_spike:   Math.abs(pct) >= 2.0,
      is_crash:   pct <= -3.0,
    };
  });
} else {
  // Fallback: generate sample data if API fails
  const tickers = ['AAPL', 'META', 'GOOGL', 'MSFT', 'TSLA', 'NVDA', 'AMZN'];
  results = tickers.map(ticker => {
    const basePrice = { AAPL: 180, META: 450, GOOGL: 140, MSFT: 410, TSLA: 250, NVDA: 880, AMZN: 175 }[ticker] || 100;
    const pct = (Math.random() * 6 - 3);
    const close = Math.round(basePrice * (1 + pct/100) * 100) / 100;
    const prevClose = basePrice;
    const open = Math.round((basePrice + (close - basePrice) * 0.3) * 100) / 100;

    return {
      ticker,
      name: names[ticker],
      open,
      close,
      high: Math.round(Math.max(open, close) * 1.01 * 100) / 100,
      low: Math.round(Math.min(open, close) * 0.99 * 100) / 100,
      prev_close: prevClose,
      day_change: Math.round((close - prevClose) * 100) / 100,
      day_pct: Math.round(pct * 100) / 100,
      volume: Math.floor(Math.random() * 50000000 + 10000000),
      direction: pct >= 0 ? 'UP' : 'DOWN',
      is_spike: Math.abs(pct) >= 2.0,
      is_crash: pct <= -3.0,
    };
  });
}

const valid      = results.filter(r => r.close > 0);
const best       = valid.length > 0 ? valid.reduce((a,b) => a.day_pct > b.day_pct ? a : b) : {};
const worst      = valid.length > 0 ? valid.reduce((a,b) => a.day_pct < b.day_pct ? a : b) : {};
const crashCount = valid.filter(r => r.is_crash).length;

return [{
  json: {
    stocks:      results,
    best_today:  best.ticker  || 'N/A',
    worst_today: worst.ticker || 'N/A',
    crash_alert: crashCount >= 4,
    fetched_at:  new Date().toISOString(),
    status:      'ok'
  }
}];

// Pull from named nodes now that all three branches are merged
const priceData = $('🧮 Parse Stock Data').first().json;
const newsData  = $('📰 Fetch Market News').first().json;
const timeData  = $('🕐 Detect Morning or Evening').first().json;

const stocks   = priceData.stocks || [];
const articles = (newsData.articles || []).slice(0, 6);
const runType  = timeData.run_type || 'MORNING';

const stockSummary = stocks
  .filter(s => s.close > 0)
  .map(s => `${s.ticker} (${s.name}): Open $${s.open} | Close $${s.close} | Change ${s.day_pct >= 0 ? '+' : ''}${s.day_pct}%`)
  .join('\n');

const newsSummary = articles
  .map(a => `- ${a.title}`)
  .join('\n');

const messageText = `You are an expert stock market analyst. This is a ${runType} report for ${new Date().toDateString()}.\n\nStock Data:\n${stockSummary || 'Market data temporarily unavailable'}\n\nToday's News:\n${newsSummary || 'No news available'}\n\nReturn ONLY valid JSON, no markdown, no extra text:\n{"overall_market":"Bullish/Bearish/Neutral","market_summary":"2-3 sentence summary of today's market","top_mover":"which stock moved most and why","news_impact":"how today's news is affecting prices","biggest_risk":"biggest risk to watch today","opportunity":"best opportunity today","anthropic_sentiment":"Anthropic AI company sentiment from news","tomorrow_outlook":"brief prediction for tomorrow","ratings":{"AAPL":"Buy/Hold/Sell","META":"Buy/Hold/Sell","GOOGL":"Buy/Hold/Sell","MSFT":"Buy/Hold/Sell","TSLA":"Buy/Hold/Sell","NVDA":"Buy/Hold/Sell","AMZN":"Buy/Hold/Sell"}}`;

return [{
  json: {
    cohereBody: JSON.stringify({
      model:    'command-r-plus-08-2024',
      messages: [{ role: 'user', content: messageText }]
    }),
    stocks:      stocks,
    articles:    articles.map(a => ({
      title:  a.title  || '',
      source: a.source?.name || '',
      url:    a.url    || ''
    })),
    run_type:    runType,
    best_today:  priceData.best_today  || 'N/A',
    worst_today: priceData.worst_today || 'N/A',
    crash_alert: priceData.crash_alert || false
  }
}];

const cohereResp = $input.first().json;
const promptData = $('📝 Build Cohere Prompt').first().json;

// Parse Cohere v2 response
const raw = cohereResp?.message?.content?.[0]?.text
         || cohereResp?.text
         || '';

let ai = {};
try {
  const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  ai = JSON.parse(cleaned);
} catch(e) {
  ai = {
    overall_market:      'Neutral',
    market_summary:      'AI analysis unavailable right now.',
    top_mover:           'N/A',
    news_impact:         'N/A',
    biggest_risk:        'N/A',
    opportunity:         'N/A',
    anthropic_sentiment: 'N/A',
    tomorrow_outlook:    'N/A',
    ratings:             {}
  };
}

const stocks    = promptData.stocks   || [];
const articles  = promptData.articles || [];
const isMorning = promptData.run_type === 'MORNING';
const mColor    = ai.overall_market === 'Bullish' ? '#00c853'
                : ai.overall_market === 'Bearish' ? '#f44336'
                : '#ff8800';
const hColor    = isMorning ? '#00d4ff' : '#bc8cff';

const stockRows = stocks.filter(s => s.close > 0).map(s => {
  const c      = s.day_pct >= 0 ? '#00c853' : '#f44336';
  const arrow  = s.day_pct >= 0 ? '&#9650;' : '&#9660;';
  const rating = (ai.ratings || {})[s.ticker] || 'Hold';
  const rc     = rating === 'Buy'  ? '#00c853'
               : rating === 'Sell' ? '#f44336'
               : '#ff8800';
  return `<tr>
    <td style='padding:10px 14px;color:#fff;font-weight:700;border-bottom:1px solid #1a1a35;'>${s.ticker}</td>
    <td style='padding:10px 14px;color:#aaa;border-bottom:1px solid #1a1a35;'>${s.name}</td>
    <td style='padding:10px 14px;color:#fff;font-family:monospace;border-bottom:1px solid #1a1a35;'>$${s.open}</td>
    <td style='padding:10px 14px;color:#fff;font-family:monospace;border-bottom:1px solid #1a1a35;'>$${s.close}</td>
    <td style='padding:10px 14px;color:${c};font-weight:700;border-bottom:1px solid #1a1a35;'>${arrow} ${s.day_pct >= 0 ? '+' : ''}${s.day_pct}%</td>
    <td style='padding:10px 14px;border-bottom:1px solid #1a1a35;'><span style='background:${rc}22;border:1px solid ${rc};color:${rc};padding:2px 8px;border-radius:100px;font-size:11px;font-weight:700;'>${rating}</span></td>
  </tr>`;
}).join('');

const newsHtml = articles.slice(0,5).map(a =>
  `<div style='background:#1a1a2e;border-left:3px solid ${hColor};padding:10px 14px;margin:6px 0;border-radius:0 6px 6px 0;'>
    <a href='${a.url}' style='color:#fff;text-decoration:none;font-size:13px;font-weight:600;'>${a.title}</a>
    <div style='color:#555;font-size:11px;margin-top:3px;'>${a.source}</div>
  </div>`
).join('');

const crashBanner = promptData.crash_alert
  ? `<div style='background:#f4433622;border:2px solid #f44336;border-radius:8px;padding:16px 20px;margin-bottom:20px;text-align:center;'>
      <div style='color:#f44336;font-size:18px;font-weight:800;'>&#128680; MARKET CRASH ALERT</div>
      <p style='color:#ff8888;margin:6px 0 0;font-size:13px;'>Multiple stocks falling hard — check your portfolio immediately!</p>
    </div>`
  : '';

const html = `<div style='background:#0a0a1a;font-family:Arial,sans-serif;max-width:700px;margin:0 auto;border-radius:12px;overflow:hidden;border:1px solid #1a1a3a;'>
  <div style='background:linear-gradient(135deg,#0a0a1a,#0d1b2a);border-bottom:2px solid ${hColor};padding:28px 32px;'>
    <div style='font-size:11px;color:${hColor};letter-spacing:3px;text-transform:uppercase;margin-bottom:8px;'>AI STOCK MONITOR &middot; ${new Date().toDateString().toUpperCase()}</div>
    <h1 style='margin:0;font-size:26px;color:#fff;'>${isMorning ? '&#127749; Good Morning &mdash; Market Open Report' : '&#127746; Market Closed &mdash; End of Day Report'}</h1>
    <p style='margin:8px 0 0;color:#666;font-size:13px;'>Apple &middot; Meta &middot; Google &middot; Microsoft &middot; Tesla &middot; NVIDIA &middot; Amazon + Anthropic News</p>
    <p style='margin:4px 0 0;font-size:11px;color:#333;'>Powered by Cohere AI &middot; Financial Modeling Prep &middot; NewsAPI &middot; n8n</p>
  </div>
  <div style='padding:24px 32px;background:#0d0d20;'>
    ${crashBanner}
    <div style='background:${mColor}11;border:1px solid ${mColor}44;border-radius:8px;padding:16px 20px;margin-bottom:24px;'>
      <div style='color:${mColor};font-size:12px;font-weight:700;letter-spacing:2px;text-transform:uppercase;margin-bottom:6px;'>Market Sentiment: ${ai.overall_market}</div>
      <p style='color:#ccc;margin:0;font-size:14px;line-height:1.6;'>${ai.market_summary}</p>
    </div>
    <h2 style='color:#fff;font-size:16px;margin:0 0 12px;border-bottom:1px solid #1a1a35;padding-bottom:8px;'>&#128200; Stock Prices + AI Ratings</h2>
    <table style='width:100%;border-collapse:collapse;background:#111126;border-radius:8px;overflow:hidden;margin-bottom:24px;'>
      <thead><tr style='background:#1a1a35;'>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Ticker</th>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Company</th>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Open</th>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Close</th>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Change</th>
        <th style='padding:10px 14px;text-align:left;color:#666;font-size:11px;text-transform:uppercase;'>Rating</th>
      </tr></thead>
      <tbody>${stockRows || `<tr><td colspan='6' style='padding:20px;text-align:center;color:#666;'>Market data loading...</td></tr>`}</tbody>
    </table>
    <h2 style='color:#fff;font-size:16px;margin:0 0 12px;border-bottom:1px solid #1a1a35;padding-bottom:8px;'>&#129302; AI Analysis</h2>
    <div style='background:#111126;border-radius:8px;padding:18px 20px;margin-bottom:24px;'>
      <p style='color:#aaa;font-size:13px;margin:0 0 12px;line-height:1.7;'><strong style='color:#00d4ff;'>Top Mover:</strong> ${ai.top_mover}</p>
      <p style='color:#aaa;font-size:13px;margin:0 0 12px;line-height:1.7;'><strong style='color:#00d4ff;'>News Impact:</strong> ${ai.news_impact}</p>
      <p style='color:#aaa;font-size:13px;margin:0 0 12px;line-height:1.7;'><strong style='color:#f44336;'>Risk:</strong> ${ai.biggest_risk}</p>
      <p style='color:#aaa;font-size:13px;margin:0 0 12px;line-height:1.7;'><strong style='color:#00c853;'>Opportunity:</strong> ${ai.opportunity}</p>
      <p style='color:#aaa;font-size:13px;margin:0 0 12px;line-height:1.7;'><strong style='color:#bc8cff;'>Anthropic Pulse:</strong> ${ai.anthropic_sentiment}</p>
      <p style='color:#aaa;font-size:13px;margin:0;line-height:1.7;'><strong style='color:#ff8800;'>Tomorrow:</strong> ${ai.tomorrow_outlook}</p>
    </div>
    <h2 style='color:#fff;font-size:16px;margin:0 0 12px;border-bottom:1px solid #1a1a35;padding-bottom:8px;'>&#128240; Latest News</h2>
    ${newsHtml || '<p style="color:#666;font-size:13px;">No relevant news found today.</p>'}
  </div>
  <div style='background:#050510;padding:14px 32px;text-align:center;font-size:11px;color:#444;border-radius:0 0 12px 12px;'>Generated by AI Stock Monitor &middot; Yahoo Finance + Cohere AI + n8n &middot; Not financial advice &middot; ${new Date().toISOString()}</div>
</div>`;

return [{
  json: {
    html,
    subject: `${isMorning ? 'Market Open' : 'Market Closed'} -- ${ai.overall_market} | Best: ${promptData.best_today} | Worst: ${promptData.worst_today} -- ${new Date().toDateString()}`
  }
}];
